import React, { useState } from 'react';
import { FiPackage, FiTruck, FiBox, FiGlobe, FiBriefcase, FiSearch, FiCpu, FiX } from 'react-icons/fi';

const Home = () => {
  const [showForm, setShowForm] = useState(false);
  const [selectedService, setSelectedService] = useState('');
  const [subService, setSubService] = useState('');
  const [formData, setFormData] = useState({ name: '', phone: '', from: '', to: '', weight: '' });

  // Tumchi list ithe add keli aahe
  const courierOptions = [
    "Domestic Courier",
    "International Courier",
    "Express / Same Day Delivery",
    "Surface Courier (Economy)",
    "Air Courier",
    "Bulk Courier (MSME / Business)",
    "In-City Courier (Local)",
    "Government Speed Post (Postal)",
    "Safe Document Service (Priority)"
  ];

  const handleWhatsApp = (e) => {
    e.preventDefault();
    const finalService = subService ? `${selectedService} (${subService})` : selectedService;
    const message = `*Navin Booking - Apni Manzil*%0A--------------------------%0A*Service:* ${finalService}%0A*Customer:* ${formData.name}%0A*Phone:* ${formData.phone}%0A*From:* ${formData.from}%0A*To:* ${formData.to}%0A*Weight:* ${formData.weight}`;
    window.open(`https://wa.me/91XXXXXXXXXX?text=${message}`, '_blank');
    setShowForm(false);
  };

  const ServiceCard = ({ icon, title, desc, btnColor }) => (
    <div className="col">
      <div className="premium-card h-100 border-0 shadow-sm text-center p-4 rounded-4 bg-white">
        <div className="mb-3 d-flex justify-content-center" style={{ fontSize: '3rem', color: btnColor }}>{icon}</div>
        <h6 className="fw-bold mb-2">{title}</h6>
        <p className="text-muted small mb-4">{desc}</p>
        <button 
          onClick={() => { 
            setSelectedService(title); 
            setSubService(''); // Reset sub-service
            setShowForm(true); 
          }}
          className="btn btn-sm w-100 rounded-pill text-white fw-bold py-2" 
          style={{ backgroundColor: btnColor, border: 'none' }}>
          Select
        </button>
      </div>
    </div>
  );

  return (
    <div className="container py-5 mt-4">
      <div className="text-center mb-5">
        <h1 className="fw-bold text-dark display-5 mb-2">Logistics Aggregator</h1>
        <p className="text-muted">Choose the best service for your needs</p>
      </div>

      <div className="row row-cols-1 row-cols-md-2 row-cols-lg-4 g-4 justify-content-center mb-5">
        <ServiceCard icon={<FiPackage />} title="Courier Services" desc="Domestic & International" btnColor="#27ae60" />
        <ServiceCard icon={<FiTruck />} title="Transport" desc="Heavy & Full Truck" btnColor="#d35400" />
        <ServiceCard icon={<FiBox />} title="Packers & Movers" desc="Home & Office Shifting" btnColor="#f39c12" />
        <ServiceCard icon={<FiBriefcase />} title="Business Logistics" desc="For MSMEs" btnColor="#2980b9" />
      </div>

      {/* Booking Form Modal */}
      {showForm && (
        <div className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center" 
             style={{ background: 'rgba(0,0,0,0.6)', zIndex: 1050 }}>
          <div className="bg-white p-4 rounded-4 shadow-lg position-relative" style={{ width: '100%', maxWidth: '450px' }}>
            <button className="position-absolute top-0 end-0 m-3 btn border-0" onClick={() => setShowForm(false)}><FiX size={24} /></button>
            <h4 className="fw-bold text-primary mb-3">Book {selectedService}</h4>
            
            <form onSubmit={handleWhatsApp}>
              {/* JAR COURIER SELECT KELA ASEL TAR OPTIONS DAKHVA */}
              {selectedService === "Courier Services" && (
                <div className="mb-3">
                  <label className="form-label small fw-bold">Select Specific Service:</label>
                  <select className="form-select border-primary" required onChange={(e) => setSubService(e.target.value)}>
                    <option value="">-- Choose Option --</option>
                    {courierOptions.map((opt, index) => (
                      <option key={index} value={opt}>{opt}</option>
                    ))}
                  </select>
                </div>
              )}

              <div className="mb-2"><input type="text" placeholder="Full Name" className="form-control" required onChange={(e)=>setFormData({...formData, name: e.target.value})} /></div>
              <div className="mb-2"><input type="number" placeholder="WhatsApp Number" className="form-control" required onChange={(e)=>setFormData({...formData, phone: e.target.value})} /></div>
              <div className="row g-2 mb-2">
                <div className="col"><input type="text" placeholder="From (City)" className="form-control" required onChange={(e)=>setFormData({...formData, from: e.target.value})} /></div>
                <div className="col"><input type="text" placeholder="To (City)" className="form-control" required onChange={(e)=>setFormData({...formData, to: e.target.value})} /></div>
              </div>
              <div className="mb-3"><input type="text" placeholder="Approx Weight" className="form-control" required onChange={(e)=>setFormData({...formData, weight: e.target.value})} /></div>
              
              <button type="submit" className="btn btn-success w-100 fw-bold rounded-pill shadow-sm">
                Confirm on WhatsApp
              </button>
            </form>
          </div>
        </div>
      )}

      <style>{`.premium-card:hover { transform: translateY(-10px); transition: 0.3s; }`}</style>
    </div>
  );
};

export default Home;
